// n8n Code node v3 — remap webhook → shape `media.*` esperado por
// `/api/internal/whatsapp/ocr-process`. Firma HMAC v2 con
// FACTURAIA_SIGNING_SECRET (vivo en env n8n desde 2026-05-30) — sustituye
// al legacy `x-service-key`. El backend acepta v2 estrictamente y legacy
// hasta `SIGNING_LEGACY_UNTIL` (2026-07-30); migramos aquí para cerrar el
// agujero antes de la fecha.

const crypto = require('crypto');

const body = $('Webhook OCR').first().json.body || $input.first().json;

const orgId = body.org_id;
const orgNombre = body.org_nombre || '';
const facturaId = body.factura_id;
const bandejaId = body.bandeja_id;
const base64 = body.file_base64;
const mime = body.mime_type || 'application/octet-stream';
const filename = body.nombre_archivo || 'factura.pdf';

if (!facturaId) {
  throw new Error('OCR webhook: factura_id ausente — actualiza /api/upload (PR #103 ya mergeado) y verifica deploy Dokploy.');
}
if (!bandejaId) throw new Error('OCR webhook: bandeja_id ausente');
if (!orgId) throw new Error('OCR webhook: org_id ausente');
if (!base64) throw new Error('OCR webhook: file_base64 ausente');

const SIGNING_SECRET = $env.FACTURAIA_SIGNING_SECRET;
if (!SIGNING_SECRET) {
  throw new Error('OCR webhook: FACTURAIA_SIGNING_SECRET no disponible en env del container n8n. Verifica compose Dokploy.');
}

const targetBody = JSON.stringify({
  org_id: orgId,
  org_nombre: orgNombre,
  factura_id: facturaId,
  bandeja_id: bandejaId,
  media: { base64, mime, filename }
});

const appUrl = ($env.APP_URL || 'https://app.tufacturaia.com').replace(/\/$/, '');
const path = '/api/internal/whatsapp/ocr-process';

// Firma v2: payload = `${t}.${METHOD}.${pathWithSearch}.${bodyHash}`
const t = Math.floor(Date.now() / 1000);
const bodyHash = crypto.createHash('sha256').update(targetBody, 'utf8').digest('hex');
const payload = `${t}.POST.${path}.${bodyHash}`;
const sig = crypto.createHmac('sha256', SIGNING_SECRET).update(payload, 'utf8').digest('hex');
const signatureHeader = `t=${t},v1=${sig}`;

return [{ json: {
  target_url: `${appUrl}${path}`,
  signature_header: signatureHeader,
  target_body: targetBody,
  request_meta: { bandeja_id: bandejaId, factura_id: facturaId, org_id: orgId }
}}];

